      chatGPTServer:          val('chatGPTServer'),
      chatGPTApiKey:          val('chatGPTApiKey'),
      chatGPTModel:           val('chatGPTModelManual')  || val('chatGPTModel'),
      claudeServer:           val('claudeServer'),
